export const nextGeneration = (livingCells: Cell[]): Cell[] => {
  const liveSet = new Set(livingCells.map(([x, y]) => `${x},${y}`));
  return livingCells.filter(([x, y]) => {
    let neighbors = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveSet.has(`${x + dx},${y + dy}`)) neighbors++;
      }
    }
    return neighbors === 2;
  });
};

